{"language": "html", "code": "<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>UX Competency Scorecard</title>
<link href="https://fonts.googleapis.com/css2?family=Bebas+Neue&family=DM+Sans:wght@300;400;500;600;700&family=Space+Mono:wght@400;700&display=swap" rel="stylesheet">
<style>
  :root {
    --bg: #08090e;
    --surface: #10121a;
    --surface2: #181b27;
    --border: #252836;
    --border-accent: #2d3147;
    --text: #e8eaf0;
    --text-dim: #6b7194;
    --text-muted: #3d4162;
    --coral: #ff4d6a;
    --coral-glow: rgba(255, 77, 106, 0.15);
    --teal: #00e5c7;
    --teal-glow: rgba(0, 229, 199, 0.12);
    --amber: #ffc645;
    --amber-glow: rgba(255, 198, 69, 0.12);
    --purple: #a78bfa;
    --purple-glow: rgba(167, 139, 250, 0.12);
    --blue: #38bdf8;
    --blue-glow: rgba(56, 189, 248, 0.12);
    --pink: #f472b6;
  }

  * { margin: 0; padding: 0; box-sizing: border-box; }

  body {
    font-family: 'DM Sans', sans-serif;
    background: var(--bg);
    color: var(--text);
    min-height: 100vh;
    -webkit-font-smoothing: antialiased;
  }

  .grain {
    position: fixed;
    top: 0; left: 0; right: 0; bottom: 0;
    pointer-events: none;
    z-index: 9999;
    opacity: 0.03;
    background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)'/%3E%3C/svg%3E");
  }

  .page {
    max-width: 1100px;
    margin: 0 auto;
    padding: 48px 32px 80px;
    position: relative;
  }

  /* HEADER */
  .header {
    text-align: center;
    margin-bottom: 56px;
    position: relative;
  }

  .header::after {
    content: '';
    position: absolute;
    bottom: -28px;
    left: 50%;
    transform: translateX(-50%);
    width: 80px;
    height: 2px;
    background: linear-gradient(90deg, transparent, var(--coral), transparent);
  }

  .tag {
    font-family: 'Space Mono', monospace;
    font-size: 11px;
    letter-spacing: 3px;
    text-transform: uppercase;
    color: var(--coral);
    margin-bottom: 16px;
    display: inline-block;
    padding: 6px 16px;
    border: 1px solid rgba(255, 77, 106, 0.25);
    border-radius: 2px;
    background: var(--coral-glow);
  }

  h1 {
    font-family: 'Bebas Neue', sans-serif;
    font-size: clamp(48px, 7vw, 84px);
    line-height: 0.92;
    letter-spacing: -1px;
    color: var(--text);
    margin-bottom: 12px;
  }

  h1 span {
    display: block;
    background: linear-gradient(135deg, var(--coral), var(--amber));
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
  }

  .subtitle {
    font-size: 15px;
    color: var(--text-dim);
    font-weight: 300;
    max-width: 500px;
    margin: 0 auto;
    line-height: 1.6;
  }

  /* NAME INPUT */
  .name-section {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 16px;
    margin-bottom: 48px;
    flex-wrap: wrap;
  }

  .name-label {
    font-family: 'Space Mono', monospace;
    font-size: 11px;
    letter-spacing: 2px;
    text-transform: uppercase;
    color: var(--text-muted);
  }

  .name-input {
    background: var(--surface);
    border: 1px solid var(--border);
    color: var(--text);
    font-family: 'DM Sans', sans-serif;
    font-size: 16px;
    padding: 10px 20px;
    border-radius: 4px;
    width: 280px;
    transition: border-color 0.3s;
    outline: none;
  }

  .name-input:focus {
    border-color: var(--coral);
    box-shadow: 0 0 0 3px var(--coral-glow);
  }

  .name-input::placeholder {
    color: var(--text-muted);
  }

  .date-display {
    font-family: 'Space Mono', monospace;
    font-size: 11px;
    color: var(--text-muted);
    letter-spacing: 1px;
  }

  /* COMPETENCY GRID */
  .grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 16px;
    margin-bottom: 56px;
  }

  @media (max-width: 700px) {
    .grid { grid-template-columns: 1fr; }
  }

  .comp-card {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 8px;
    padding: 24px;
    position: relative;
    overflow: hidden;
    transition: border-color 0.3s, box-shadow 0.3s;
  }

  .comp-card:hover {
    border-color: var(--border-accent);
  }

  .comp-card.active {
    box-shadow: 0 0 24px var(--glow-color, var(--coral-glow));
  }

  .comp-number {
    position: absolute;
    top: 16px;
    right: 20px;
    font-family: 'Bebas Neue', sans-serif;
    font-size: 32px;
    color: var(--text-muted);
    opacity: 0.4;
    line-height: 1;
  }

  .comp-icon {
    width: 36px;
    height: 36px;
    border-radius: 8px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 18px;
    margin-bottom: 14px;
    border: 1px solid;
  }

  .comp-name {
    font-weight: 700;
    font-size: 16px;
    margin-bottom: 4px;
    letter-spacing: -0.2px;
  }

  .comp-desc {
    font-size: 12px;
    color: var(--text-dim);
    line-height: 1.5;
    margin-bottom: 18px;
  }

  /* RATING DOTS */
  .rating {
    display: flex;
    align-items: center;
    gap: 6px;
  }

  .rating-label {
    font-family: 'Space Mono', monospace;
    font-size: 9px;
    letter-spacing: 1px;
    text-transform: uppercase;
    color: var(--text-muted);
    width: 60px;
    flex-shrink: 0;
  }

  .rating-label.end {
    text-align: right;
  }

  .dots {
    display: flex;
    gap: 6px;
    flex: 1;
    justify-content: center;
  }

  .dot {
    width: 32px;
    height: 32px;
    border-radius: 50%;
    border: 2px solid var(--border);
    cursor: pointer;
    transition: all 0.2s ease;
    position: relative;
    background: transparent;
  }

  .dot:hover {
    border-color: var(--dot-color, var(--coral));
    transform: scale(1.15);
  }

  .dot.filled {
    background: var(--dot-color, var(--coral));
    border-color: var(--dot-color, var(--coral));
    box-shadow: 0 0 12px var(--dot-glow, var(--coral-glow));
  }

  .dot-num {
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    font-family: 'Space Mono', monospace;
    font-size: 10px;
    color: var(--text-muted);
    pointer-events: none;
    transition: color 0.2s;
  }

  .dot.filled .dot-num {
    color: var(--bg);
    font-weight: 700;
  }

  .score-display {
    font-family: 'Bebas Neue', sans-serif;
    font-size: 28px;
    color: var(--dot-color, var(--coral));
    margin-left: 8px;
    min-width: 24px;
    text-align: center;
    line-height: 1;
    opacity: 0;
    transition: opacity 0.3s;
  }

  .score-display.visible {
    opacity: 1;
  }

  /* RESULTS SECTION */
  .results {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 12px;
    padding: 40px;
    text-align: center;
    position: relative;
    overflow: hidden;
    margin-bottom: 40px;
  }

  .results::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 2px;
    background: linear-gradient(90deg, var(--coral), var(--amber), var(--teal), var(--purple));
  }

  .results-tag {
    font-family: 'Space Mono', monospace;
    font-size: 10px;
    letter-spacing: 3px;
    text-transform: uppercase;
    color: var(--text-muted);
    margin-bottom: 16px;
  }

  .archetype-name {
    font-family: 'Bebas Neue', sans-serif;
    font-size: clamp(36px, 5vw, 56px);
    line-height: 1;
    margin-bottom: 8px;
    transition: all 0.5s;
  }

  .archetype-desc {
    font-size: 14px;
    color: var(--text-dim);
    max-width: 500px;
    margin: 0 auto 32px;
    line-height: 1.6;
  }

  .total-score {
    display: inline-flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 24px;
  }

  .total-num {
    font-family: 'Bebas Neue', sans-serif;
    font-size: 64px;
    line-height: 1;
  }

  .total-max {
    font-family: 'Space Mono', monospace;
    font-size: 14px;
    color: var(--text-muted);
  }

  /* RADAR CHART */
  .radar-wrap {
    display: flex;
    justify-content: center;
    margin: 32px 0 16px;
  }

  /* BAR BREAKDOWN */
  .bars {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 10px 32px;
    max-width: 600px;
    margin: 24px auto 0;
    text-align: left;
  }

  @media (max-width: 600px) {
    .bars { grid-template-columns: 1fr; }
  }

  .bar-row {
    display: flex;
    align-items: center;
    gap: 10px;
  }

  .bar-label {
    font-size: 11px;
    color: var(--text-dim);
    width: 110px;
    flex-shrink: 0;
    text-align: right;
  }

  .bar-track {
    flex: 1;
    height: 6px;
    background: var(--surface2);
    border-radius: 3px;
    overflow: hidden;
  }

  .bar-fill {
    height: 100%;
    border-radius: 3px;
    transition: width 0.6s ease;
  }

  .bar-val {
    font-family: 'Space Mono', monospace;
    font-size: 11px;
    color: var(--text-dim);
    width: 20px;
  }

  /* ARCHETYPE LEGEND */
  .legend {
    margin-top: 48px;
    padding-top: 32px;
    border-top: 1px solid var(--border);
  }

  .legend-title {
    font-family: 'Space Mono', monospace;
    font-size: 10px;
    letter-spacing: 3px;
    text-transform: uppercase;
    color: var(--text-muted);
    text-align: center;
    margin-bottom: 24px;
  }

  .archetypes-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
    gap: 12px;
  }

  .arch-card {
    padding: 16px;
    border-radius: 6px;
    border: 1px solid var(--border);
    background: var(--surface2);
    transition: border-color 0.3s, background 0.3s;
  }

  .arch-card.matched {
    border-color: var(--match-color);
    background: var(--match-glow);
  }

  .arch-label {
    font-weight: 700;
    font-size: 13px;
    margin-bottom: 4px;
  }

  .arch-focus {
    font-size: 11px;
    color: var(--text-dim);
    line-height: 1.4;
  }

  /* FOOTER */
  .footer {
    text-align: center;
    padding-top: 32px;
    border-top: 1px solid var(--border);
  }

  .footer-logo {
    font-family: 'Bebas Neue', sans-serif;
    font-size: 18px;
    letter-spacing: 2px;
    color: var(--text-muted);
    margin-bottom: 4px;
  }

  .footer-sub {
    font-family: 'Space Mono', monospace;
    font-size: 9px;
    letter-spacing: 2px;
    text-transform: uppercase;
    color: var(--text-muted);
    opacity: 0.5;
  }

  /* RESET BUTTON */
  .reset-btn {
    background: transparent;
    border: 1px solid var(--border);
    color: var(--text-dim);
    font-family: 'Space Mono', monospace;
    font-size: 10px;
    letter-spacing: 2px;
    text-transform: uppercase;
    padding: 8px 20px;
    border-radius: 4px;
    cursor: pointer;
    transition: all 0.3s;
    margin-top: 16px;
  }

  .reset-btn:hover {
    border-color: var(--coral);
    color: var(--coral);
  }

  /* PRINT STYLES */
  @media print {
    body { background: #fff; color: #111; }
    .grain { display: none; }
    .page { padding: 24px; }
    .comp-card { border-color: #ddd; background: #fafafa; break-inside: avoid; }
    .results { background: #fafafa; border-color: #ddd; }
    .dot { border-color: #ccc; }
    .dot.filled { print-color-adjust: exact; -webkit-print-color-adjust: exact; }
    .name-input { border-color: #ccc; }
    .reset-btn { display: none; }
    h1 { -webkit-text-fill-color: #111; background: none; }
    h1 span { -webkit-text-fill-color: #c0392b; background: none; }
    .comp-name, .bar-label, .arch-label { color: #111; }
    .comp-desc, .subtitle, .archetype-desc, .arch-focus { color: #555; }
    .results-tag, .legend-title, .footer-logo, .footer-sub, .date-display, .name-label, .rating-label { color: #888; }
  }
</style>
</head>
<body>

<div class="grain"></div>

<div class="page" id="app"></div>

<script src="https://cdnjs.cloudflare.com/ajax/libs/react/18.2.0/umd/react.production.min.js"></script>
<script src="https://cdnjs.cloudflare.com/ajax/libs/react-dom/18.2.0/umd/react-dom.production.min.js"></script>
<script src="https://cdnjs.cloudflare.com/ajax/libs/babel-standalone/7.23.9/babel.min.js"></script>
<script src="https://cdnjs.cloudflare.com/ajax/libs/d3/7.8.5/d3.min.js"></script>

<script type="text/babel">
const { useState, useCallback, useMemo, useRef, useEffect } = React;

const COMPETENCIES = [
  {
    id: 'research',
    name: 'User Research',
    desc: 'Interviews, usability testing, survey design, synthesis, and insight generation',
    icon: '🔍',
    color: '#ff4d6a',
    glow: 'rgba(255,77,106,0.15)',
  },
  {
    id: 'ia',
    name: 'Information Architecture',
    desc: 'Content structure, navigation design, taxonomy, card sorting, and sitemaps',
    icon: '🏗',
    color: '#ff8a4d',
    glow: 'rgba(255,138,77,0.15)',
  },
  {
    id: 'interaction',
    name: 'Interaction Design',
    desc: 'Flows, wireframes, prototyping, micro-interactions, and behavioral patterns',
    icon: '⚡',
    color: '#ffc645',
    glow: 'rgba(255,198,69,0.15)',
  },
  {
    id: 'visual',
    name: 'Visual Design',
    desc: 'Layout, typography, color theory, iconography, and brand expression',
    icon: '🎨',
    color: '#4ddb6a',
    glow: 'rgba(77,219,106,0.15)',
  },
  {
    id: 'systems',
    name: 'Design Systems',
    desc: 'Component libraries, design tokens, documentation, governance, and scalability',
    icon: '🧱',
    color: '#00e5c7',
    glow: 'rgba(0,229,199,0.15)',
  },
  {
    id: 'accessibility',
    name: 'Accessibility',
    desc: 'WCAG compliance, assistive tech, inclusive patterns, and universal design',
    icon: '♿',
    color: '#38bdf8',
    glow: 'rgba(56,189,248,0.15)',
  },
  {
    id: 'strategy',
    name: 'Product Strategy',
    desc: 'Roadmapping, metrics, stakeholder alignment, business models, and OKRs',
    icon: '🧭',
    color: '#818cf8',
    glow: 'rgba(129,140,248,0.15)',
  },
  {
    id: 'leadership',
    name: 'Design Leadership',
    desc: 'Team building, mentoring, critique facilitation, and organizational influence',
    icon: '👑',
    color: '#a78bfa',
    glow: 'rgba(167,139,250,0.15)',
  },
  {
    id: 'ops',
    name: 'Design Operations',
    desc: 'Process optimization, tooling, team scaling, budgets, and workflow management',
    icon: '⚙️',
    color: '#f472b6',
    glow: 'rgba(244,114,182,0.15)',
  },
  {
    id: 'craft',
    name: 'Prototyping & Craft',
    desc: 'High-fidelity execution, motion design, code awareness, and tool mastery',
    icon: '✦',
    color: '#fb7185',
    glow: 'rgba(251,113,133,0.15)',
  },
];

const ARCHETYPES = [
  {
    name: 'The Researcher',
    color: '#ff4d6a',
    glow: 'rgba(255,77,106,0.08)',
    focus: 'Deep in discovery — lives for insight and evidence-based design',
    peaks: ['research', 'strategy', 'accessibility'],
  },
  {
    name: 'The Craftsperson',
    color: '#ffc645',
    glow: 'rgba(255,198,69,0.08)',
    focus: 'Pixel-perfect execution — obsessed with polish, motion, and detail',
    peaks: ['visual', 'craft', 'interaction'],
  },
  {
    name: 'The Architect',
    color: '#00e5c7',
    glow: 'rgba(0,229,199,0.08)',
    focus: 'Systems thinker — builds scalable foundations others can build on',
    peaks: ['systems', 'ia', 'ops'],
  },
  {
    name: 'The Strategist',
    color: '#818cf8',
    glow: 'rgba(129,140,248,0.08)',
    focus: 'Big-picture navigator — connects design decisions to business outcomes',
    peaks: ['strategy', 'leadership', 'research'],
  },
  {
    name: 'The Generalist',
    color: '#f472b6',
    glow: 'rgba(244,114,182,0.08)',
    focus: 'Jack of all trades — adaptable, cross-functional, fills any gap',
    peaks: [],
  },
  {
    name: 'The Champion',
    color: '#a78bfa',
    glow: 'rgba(167,139,250,0.08)',
    focus: 'Design evangelist — builds teams, culture, and organizational buy-in',
    peaks: ['leadership', 'ops', 'strategy'],
  },
];

function getArchetype(scores) {
  const total = Object.values(scores).reduce((a, b) => a + b, 0);
  if (total === 0) return null;

  const vals = Object.values(scores);
  const avg = total / vals.length;
  const variance = vals.reduce((sum, v) => sum + Math.pow(v - avg, 2), 0) / vals.length;

  // Generalist: low variance means even spread
  if (variance < 0.8 && total >= 20) {
    return ARCHETYPES.find(a => a.name === 'The Generalist');
  }

  let bestMatch = null;
  let bestScore = -1;

  for (const arch of ARCHETYPES) {
    if (arch.peaks.length === 0) continue;
    const peakScore = arch.peaks.reduce((sum, p) => sum + (scores[p] || 0), 0);
    const normalizedScore = peakScore / arch.peaks.length;
    if (normalizedScore > bestScore) {
      bestScore = normalizedScore;
      bestMatch = arch;
    }
  }

  return bestMatch;
}

// Radar Chart Component
function RadarChart({ scores, size = 260 }) {
  const center = size / 2;
  const radius = size / 2 - 30;
  const levels = 5;
  const competencyIds = COMPETENCIES.map(c => c.id);
  const angleStep = (Math.PI * 2) / competencyIds.length;

  const getPoint = (index, value) => {
    const angle = angleStep * index - Math.PI / 2;
    const r = (value / 5) * radius;
    return { x: center + r * Math.cos(angle), y: center + r * Math.sin(angle) };
  };

  // Grid rings
  const rings = Array.from({ length: levels }, (_, i) => {
    const r = ((i + 1) / levels) * radius;
    const points = competencyIds.map((_, j) => {
      const angle = angleStep * j - Math.PI / 2;
      return `${center + r * Math.cos(angle)},${center + r * Math.sin(angle)}`;
    }).join(' ');
    return points;
  });

  // Data polygon
  const dataPoints = competencyIds.map((id, i) => {
    const pt = getPoint(i, scores[id] || 0);
    return `${pt.x},${pt.y}`;
  }).join(' ');

  // Axis lines
  const axes = competencyIds.map((_, i) => {
    const angle = angleStep * i - Math.PI / 2;
    return {
      x2: center + radius * Math.cos(angle),
      y2: center + radius * Math.sin(angle),
    };
  });

  // Labels
  const labels = COMPETENCIES.map((comp, i) => {
    const angle = angleStep * i - Math.PI / 2;
    const lr = radius + 18;
    return {
      x: center + lr * Math.cos(angle),
      y: center + lr * Math.sin(angle),
      text: comp.name.split(' ')[0],
      color: comp.color,
    };
  });

  return (
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
      {rings.map((pts, i) => (
        <polygon key={i} points={pts} fill="none" stroke="#252836" strokeWidth="1" opacity={0.5 + i * 0.1} />
      ))}
      {axes.map((ax, i) => (
        <line key={i} x1={center} y1={center} x2={ax.x2} y2={ax.y2} stroke="#252836" strokeWidth="1" />
      ))}
      <polygon
        points={dataPoints}
        fill="url(#radarGrad)"
        stroke="#ff4d6a"
        strokeWidth="2"
        opacity="0.85"
      />
      {competencyIds.map((id, i) => {
        const pt = getPoint(i, scores[id] || 0);
        const comp = COMPETENCIES[i];
        return scores[id] > 0 ? (
          <circle key={id} cx={pt.x} cy={pt.y} r="4" fill={comp.color} stroke={comp.color} strokeWidth="2" opacity="0.9" />
        ) : null;
      })}
      {labels.map((l, i) => (
        <text key={i} x={l.x} y={l.y} textAnchor="middle" dominantBaseline="middle" fill={l.color} fontSize="8" fontFamily="Space Mono, monospace" opacity="0.7">
          {l.text}
        </text>
      ))}
