function App() {
  const [name, setName] = useState('');
  const [scores, setScores] = useState({});
  const resultsRef = useRef(null);

  const today = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });

  const handleRate = useCallback((compId, value) => {
    setScores(prev => {
      const current = prev[compId];
      // Toggle off if clicking same value
      if (current === value) {
        const next = { ...prev };
        delete next[compId];
        return next;
      }
      return { ...prev, [compId]: value };
    });
  }, []);

  const totalScore = useMemo(() => Object.values(scores).reduce((a, b) => a + b, 0), [scores]);
  const ratedCount = Object.keys(scores).length;
  const archetype = useMemo(() => getArchetype(scores), [scores]);
  const allRated = ratedCount === COMPETENCIES.length;

  const handleReset = () => {
    setScores({});
    setName('');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  useEffect(() => {
    if (allRated && resultsRef.current) {
      resultsRef.current.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }
  }, [allRated]);

  return (
    <>
      {/* HEADER */}
      <div className="header">
        <div className="tag">Workshop Activity</div>
        <h1>
          UX COMPETENCY
          <span>SCORECARD</span>
        </h1>
        <p className="subtitle">
          Rate yourself honestly across 10 core design competencies.
          Discover your archetype and where to grow next.
        </p>
      </div>

      {/* NAME + DATE */}
      <div className="name-section">
        <span className="name-label">Designer</span>
        <input
          className="name-input"
          type="text"
          placeholder="Your name"
          value={name}
          onChange={e => setName(e.target.value)}
        />
        <span className="date-display">{today}</span>
      </div>

      {/* COMPETENCY GRID */}
      <div className="grid">
        {COMPETENCIES.map((comp, idx) => {
          const rated = scores[comp.id] != null;
          return (
            <div
              key={comp.id}
              className={`comp-card${rated ? ' active' : ''}`}
              style={{ '--glow-color': comp.glow, borderColor: rated ? comp.color + '40' : undefined }}
            >
              <div className="comp-number">{String(idx + 1).padStart(2, '0')}</div>
              <div className="comp-icon" style={{ background: comp.glow, borderColor: comp.color + '30', color: comp.color }}>
                {comp.icon}
              </div>
              <div className="comp-name">{comp.name}</div>
              <div className="comp-desc">{comp.desc}</div>
              <div className="rating">
                <span className="rating-label">Novice</span>
                <div className="dots">
                  {[1, 2, 3, 4, 5].map(n => (
                    <button
                      key={n}
                      className={`dot${scores[comp.id] >= n ? ' filled' : ''}`}
                      style={{ '--dot-color': comp.color, '--dot-glow': comp.glow }}
                      onClick={() => handleRate(comp.id, n)}
                      aria-label={`Rate ${comp.name} ${n} out of 5`}
                    >
                      <span className="dot-num">{n}</span>
                    </button>
                  ))}
                </div>
                <span className="rating-label end">Expert</span>
                <div className={`score-display${rated ? ' visible' : ''}`} style={{ color: comp.color }}>
                  {scores[comp.id] || ''}
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {/* RESULTS */}
      <div className="results" ref={resultsRef}>
        <div className="results-tag">Your Results — {ratedCount}/10 Rated</div>

        {allRated && archetype ? (
          <>
            <div className="archetype-name" style={{ color: archetype.color }}>
              {archetype.name}
            </div>
            <p className="archetype-desc">{archetype.focus}</p>
          </>
        ) : (
          <>
            <div className="archetype-name" style={{ color: '#3d4162' }}>
              {ratedCount === 0 ? '— — —' : 'Keep going...'}
            </div>
            <p className="archetype-desc" style={{ color: '#3d4162' }}>
              {ratedCount === 0
                ? 'Rate all 10 competencies to reveal your design archetype'
                : `${10 - ratedCount} competencies remaining`}
            </p>
          </>
        )}

        <div className="total-score">
          <span className="total-num" style={{ color: allRated && archetype ? archetype.color : 'var(--text-muted)' }}>
            {totalScore}
          </span>
          <span className="total-max">/ 50</span>
        </div>

        {/* Radar */}
        {ratedCount > 0 && (
          <div className="radar-wrap">
            <RadarChart scores={scores} />
          </div>
        )}

        {/* Bar breakdown */}
        {ratedCount > 0 && (
          <div className="bars">
            {COMPETENCIES.map(comp => (
              <div className="bar-row" key={comp.id}>
                <span className="bar-label">{comp.name}</span>
                <div className="bar-track">
                  <div
                    className="bar-fill"
                    style={{
                      width: `${((scores[comp.id] || 0) / 5) * 100}%`,
                      background: comp.color,
                      opacity: scores[comp.id] ? 0.8 : 0.15,
                    }}
                  />
                </div>
                <span className="bar-val" style={{ color: scores[comp.id] ? comp.color : 'var(--text-muted)' }}>
                  {scores[comp.id] || '—'}
                </span>
              </div>
            ))}
          </div>
        )}

        <button className="reset-btn" onClick={handleReset}>Reset All</button>
      </div>

      {/* ARCHETYPE LEGEND */}
      <div className="legend">
        <div className="legend-title">All Archetypes</div>
        <div className="archetypes-grid">
          {ARCHETYPES.map(arch => {
            const isMatch = allRated && archetype && archetype.name === arch.name;
            return (
              <div
                key={arch.name}
                className={`arch-card${isMatch ? ' matched' : ''}`}
                style={{ '--match-color': arch.color + '60', '--match-glow': arch.glow }}
              >
                <div className="arch-label" style={{ color: isMatch ? arch.color : 'var(--text)' }}>
                  {arch.name} {isMatch && '← You'}
                </div>
                <div className="arch-focus">{arch.focus}</div>
              </div>
            );
          })}
        </div>
      </div>

      {/* FOOTER */}
      <div className="footer">
        <div className="footer-logo">Jacksonville Design Community</div>
        <div className="footer-sub">UX Competency Assessment • {new Date().getFullYear()}</div>
      </div>
    </>
  );
}

ReactDOM.createRoot(document.getElementById('app')).render(<App />);
</script>
</body>
</html>
