            aria-label={`Rate ${n}`}>
            <span className="dot-num">{n}</span>
          </button>
        ))}
      </div>
      <span className="rating-label end">Expert</span>
      <div className={`score-val${value ? ' visible' : ''}`} style={{ color }}>{value || ''}</div>
    </div>
  );
}

function RadarChart({ scores, size = 280 }) {
  const c = size / 2, r = size / 2 - 32, levels = 5;
  const ids = COMPETENCIES.map(x => x.id);
  const step = (Math.PI * 2) / ids.length;
  const pt = (i, v) => {
    const a = step * i - Math.PI / 2;
    const d = (v / 5) * r;
    return { x: c + d * Math.cos(a), y: c + d * Math.sin(a) };
  };
  const rings = Array.from({ length: levels }, (_, i) => {
    const rr = ((i + 1) / levels) * r;
    return ids.map((_, j) => { const a = step * j - Math.PI / 2; return `${c + rr * Math.cos(a)},${c + rr * Math.sin(a)}`; }).join(' ');
  });
  const dataPts = ids.map((id, i) => { const p = pt(i, scores[id] || 0); return `${p.x},${p.y}`; }).join(' ');
  const labels = COMPETENCIES.map((comp, i) => {
    const a = step * i - Math.PI / 2, lr = r + 20;
    return { x: c + lr * Math.cos(a), y: c + lr * Math.sin(a), t: comp.name.split(' ')[0], color: comp.color };
  });
  return (
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
      {rings.map((p, i) => <polygon key={i} points={p} fill="none" stroke="#252836" strokeWidth="1" opacity={0.4 + i * 0.12} />)}
      {ids.map((_, i) => { const a = step * i - Math.PI / 2; return <line key={i} x1={c} y1={c} x2={c + r * Math.cos(a)} y2={c + r * Math.sin(a)} stroke="#252836" strokeWidth="1" />; })}
      <polygon points={dataPts} fill="url(#rg)" stroke="#ff4d6a" strokeWidth="2" opacity="0.85" />
      {ids.map((id, i) => { const p = pt(i, scores[id] || 0); return scores[id] > 0 ? <circle key={id} cx={p.x} cy={p.y} r="4" fill={COMPETENCIES[i].color} /> : null; })}
      {labels.map((l, i) => <text key={i} x={l.x} y={l.y} textAnchor="middle" dominantBaseline="middle" fill={l.color} fontSize="7.5" fontFamily="Space Mono, monospace" opacity="0.65">{l.t}</text>)}
      <defs><linearGradient id="rg" x1="0%" y1="0%" x2="100%" y2="100%"><stop offset="0%" stopColor="#ff4d6a" stopOpacity="0.22" /><stop offset="50%" stopColor="#a78bfa" stopOpacity="0.12" /><stop offset="100%" stopColor="#00e5c7" stopOpacity="0.18" /></linearGradient></defs>
    </svg>
  );
}

