        <div className="score-ring">
          <div className="score-big" style={{ color: progressPct > 80 && archetype ? archetype.color : 'var(--text-muted)' }}>{grandTotal}</div>
          <div className="score-label">/ {grandMax} total points</div>
        </div>

        {/* Section scores */}
        <div className="stats-row">
          {sections.map(s => (
            <div className="stat" key={s.label}>
              <div className="stat-num" style={{ color: s.color }}>{s.score}<span style={{ fontSize: 14, color: 'var(--text-muted)' }}>/{s.max}</span></div>
              <div className="stat-label">{s.label}</div>
            </div>
          ))}
        </div>

        {/* Radar */}
        {compRatedCount > 0 && (
          <div className="radar-wrap">
            <RadarChart scores={compScores} />
          </div>
