        <div className="section-scores">
          {[...COMPETENCIES.map(c => ({ label: c.name, score: compScores[c.id] || 0, max: 5, color: c.color })),
            ...SOFT_SKILLS.map(s => ({ label: s.name, score: softScores[s.id] || 0, max: 5, color: s.color }))
          ].map(row => (
            <div className="sbar-row" key={row.label}>
              <span className="sbar-label">{row.label}</span>
              <div className="sbar-track">
                <div className="sbar-fill" style={{ width: `${(row.score / row.max) * 100}%`, background: row.color, opacity: row.score ? 0.8 : 0.12 }} />
              </div>
              <span className="sbar-val" style={{ color: row.score ? row.color : 'var(--text-muted)' }}>{row.score || '—'}</span>
            </div>
          ))}
        </div>

        {/* Growth Areas */}
        {(compRatedCount > 0 || Object.values(softScores).some(v => v > 0)) && (
          <>
            <div style={{ fontFamily: 'Space Mono, monospace', fontSize: 10, letterSpacing: 3, textTransform: 'uppercase', color: 'var(--text-muted)', marginTop: 32, marginBottom: 16 }}>
              Top Growth Opportunities
            </div>
            <div className="growth-grid">
              {growthAreas.map(g => (
                <div className="growth-card" key={g.name}>
                  <div className="growth-label" style={{ color: g.color }}>{g.name}</div>
                  <div className="growth-score">{g.section} · {g.score}/5</div>
                </div>
              ))}
            </div>
          </>
        )}

        <div className="btn-row">
          <button className="btn btn-ghost" onClick={handleReset}>Reset All</button>
          <button className="btn btn-fill" onClick={() => window.print()}>Print Scorecard</button>
        </div>
      </div>

      {/* ARCHETYPE LEGEND */}
      <div className="legend">
        <div className="legend-title">All Archetypes</div>
        <div className="arch-grid">
          {ARCHETYPES.map(arch => {
            const isMatch = compRatedCount === COMPETENCIES.length && archetype && archetype.name === arch.name;
            return (
              <div key={arch.name} className={`arch-card${isMatch ? ' matched' : ''}`}
                style={{ '--m-color': arch.color + '60', '--m-glow': arch.glow }}>
                <div className="arch-name" style={{ color: isMatch ? arch.color : 'var(--text)' }}>
                  {arch.name} {isMatch && '← You'}
                </div>
                <div className="arch-focus">{arch.focus}</div>
              </div>
            );
          })}
        </div>
      </div>

      <div className="footer">
        <div className="footer-logo">Jacksonville Design Community</div>
        <div className="footer-sub">UX Designer Assessment · {new Date().getFullYear()}</div>
      </div>
    </>
  );
}

// Progress bar portal
function ProgressBar() {
  const [pct, setPct] = useState(0);
  useEffect(() => {
    const interval = setInterval(() => {
      const items = document.querySelectorAll('.dot.filled, .ladder-btn.selected, .status-btn.active:not([data-id="none"]), .check-item.checked');
      const total = 1 + 10 + 6 + 10 + 10; // career + comp + soft + assets + exp
      setPct(Math.round((items.length / total) * 100));
    }, 500);
    return () => clearInterval(interval);
  }, []);
  return (
    <div className="progress-bar-wrap">
      <div className="progress-inner">
        <span className="progress-text">{pct}% Complete</span>
        <div className="progress-track"><div className="progress-fill" style={{ width: `${pct}%` }} /></div>
      </div>
    </div>
  );
}

ReactDOM.createRoot(document.getElementById('app')).render(<App />);
ReactDOM.createRoot(document.getElementById('progress-mount')).render(<ProgressBar />);
</script>
</body>
</html>
