  .rp-arch-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 6px; }
  .rp-arch-card {
    padding: 8px 10px; border-radius: 5px; border: 1px solid var(--border); background: var(--surface2); transition: all 0.3s;
  }
  .rp-arch-card.matched { border-color: var(--m-color); background: var(--m-glow); }
  .rp-arch-card-name { font-weight: 700; font-size: 10px; margin-bottom: 1px; }
  .rp-arch-card-focus { font-size: 9px; color: var(--text-dim); line-height: 1.3; }

  /* Buttons */
  .rp-btn-row { display: flex; gap: 8px; margin-top: 16px; }
  .btn {
    font-family: 'Space Mono', monospace; font-size: 9px; letter-spacing: 1.5px;
    text-transform: uppercase; padding: 8px 16px; border-radius: 4px; cursor: pointer;
    transition: all 0.3s; flex: 1; text-align: center;
  }
  .btn-ghost { background: transparent; border: 1px solid var(--border); color: var(--text-dim); }
  .btn-ghost:hover { border-color: var(--coral); color: var(--coral); }
  .btn-fill { background: var(--coral); border: 1px solid var(--coral); color: var(--bg); }
  .btn-fill:hover { background: #ff3355; }

  .footer {
    text-align: center; padding-top: 24px; border-top: 1px solid var(--border); margin-top: 36px;
  }
  .footer-logo { font-family: 'Bebas Neue', sans-serif; font-size: 16px; letter-spacing: 2px; color: var(--text-muted); }
  .footer-sub {
    font-family: 'Space Mono', monospace; font-size: 8px; letter-spacing: 2px;
    text-transform: uppercase; color: var(--text-muted); opacity: 0.5;
  }

  @media print {
    body { background: #fff; color: #111; }
    .grain { display: none; }
    .shell { display: block; }
    .sidebar { display: none; }
    .mobile-results { display: block !important; }
    .main { max-width: 100%; padding: 20px; }
    .card, .check-item, .rp-stat, .rp-arch-card, .rp-growth-item { background: #fafafa; border-color: #ddd; break-inside: avoid; }
    .dot.filled, .ladder-btn.selected, .status-btn.active, .check-item.checked { print-color-adjust: exact; -webkit-print-color-adjust: exact; }
    h1 { -webkit-text-fill-color: #111; background: none; }
    h1 span { -webkit-text-fill-color: #c0392b; background: none; }
    .btn { display: none; }
  }
</style>
</head>
<body>
<div class="grain"></div>
<div id="app"></div>

<script src="https://cdnjs.cloudflare.com/ajax/libs/react/18.2.0/umd/react.production.min.js"></script>
