  { id: 'visual', name: 'Visual Design', desc: 'Layout, typography, color, iconography, brand expression', icon: '🎨', color: '#4ddb6a', glow: 'rgba(77,219,106,0.12)' },
  { id: 'systems', name: 'Design Systems', desc: 'Components, tokens, documentation, governance', icon: '🧱', color: '#00e5c7', glow: 'rgba(0,229,199,0.12)' },
  { id: 'accessibility', name: 'Accessibility', desc: 'WCAG, assistive tech, inclusive patterns', icon: '♿', color: '#38bdf8', glow: 'rgba(56,189,248,0.12)' },
  { id: 'strategy', name: 'Product Strategy', desc: 'Roadmapping, metrics, stakeholder alignment, OKRs', icon: '🧭', color: '#818cf8', glow: 'rgba(129,140,248,0.12)' },
  { id: 'leadership', name: 'Design Leadership', desc: 'Mentoring, critique, team building, org influence', icon: '👑', color: '#a78bfa', glow: 'rgba(167,139,250,0.12)' },
  { id: 'ops', name: 'Design Operations', desc: 'Process, tooling, team scaling, workflow management', icon: '⚙️', color: '#f472b6', glow: 'rgba(244,114,182,0.12)' },
  { id: 'craft', name: 'Prototyping & Craft', desc: 'Hi-fi execution, motion, code awareness, tool mastery', icon: '✦', color: '#fb7185', glow: 'rgba(251,113,133,0.12)' },
];

const SOFT_SKILLS = [
  { id: 'presentation', name: 'Presenting & Storytelling', desc: 'Pitching ideas, presenting to stakeholders', icon: '🎤', color: '#ff4d6a', glow: 'rgba(255,77,106,0.12)' },
  { id: 'communication', name: 'Cross-Functional Comms', desc: 'Working with engineers, PMs, marketing, execs', icon: '💬', color: '#ffc645', glow: 'rgba(255,198,69,0.12)' },
  { id: 'critique', name: 'Giving & Receiving Feedback', desc: 'Constructive critique, iterating on input', icon: '🔄', color: '#00e5c7', glow: 'rgba(0,229,199,0.12)' },
  { id: 'facilitation', name: 'Workshop Facilitation', desc: 'Leading sprints, brainstorms, alignment sessions', icon: '🧩', color: '#818cf8', glow: 'rgba(129,140,248,0.12)' },
  { id: 'negotiation', name: 'Pushback & Negotiation', desc: 'Advocating for users, defending decisions', icon: '🛡', color: '#a78bfa', glow: 'rgba(167,139,250,0.12)' },
  { id: 'timemanagement', name: 'Time & Project Mgmt', desc: 'Scoping, deadlines, managing ambiguity', icon: '⏱', color: '#f472b6', glow: 'rgba(244,114,182,0.12)' },
