  .header { text-align: center; margin-bottom: 44px; position: relative; }
  .header::after {
    content: ''; position: absolute; bottom: -22px; left: 50%; transform: translateX(-50%);
    width: 60px; height: 2px; background: linear-gradient(90deg, transparent, var(--coral), transparent);
  }
  .tag {
    font-family: 'Space Mono', monospace; font-size: 10px; letter-spacing: 3px;
    text-transform: uppercase; color: var(--coral); margin-bottom: 12px; display: inline-block;
    padding: 4px 12px; border: 1px solid; border-color: var(--coral-glow); border-radius: 2px;
